{
  "name": "ArchPrompt Pro",
  "description": "Transform snapshots of architectural projects into professional AI generation prompts with advanced environment controls.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type LightingMode = 'morning' | 'afternoon' | 'sunset' | 'night';
export type WeatherMode = 'sunny' | 'cloudy' | 'rainy' | 'post-rain';
export type StreetType = 'with-sidewalk' | 'no-sidewalk';
export type CameraAngle = 'eye-level' | 'wide' | 'close-up' | 'drone';

export interface PromptParameters {
  lighting: LightingMode;
  weather: WeatherMode;
  peopleCount: number;
  carCount: number;
  streetType: StreetType;
  cameraAngle: CameraAngle;
  environment: string;
}

export interface GeneratedPrompt {
  english: string;
  portuguese: string;
  tags: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { PromptParameters, GeneratedPrompt } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateArchitecturalPrompt = async (
  imageData: string,
  params: PromptParameters
): Promise<GeneratedPrompt> => {
  const model = ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: imageData.split(',')[1],
            },
          },
          {
            text: `Analyze this architectural project image and generate a highly professional, detailed prompt for AI image generators (like Midjourney or Stable Diffusion).

            USER SPECIFICATIONS:
            - Lighting: ${params.lighting}
            - Weather: ${params.weather}
            - Number of people: ${params.peopleCount}
            - Number of cars: ${params.carCount}
            - Street Type: ${params.streetType}
            - Camera Angle: ${params.cameraAngle}
            - Additional Environment context: ${params.environment}

            The prompt should describe materials (concrete, glass, timber), lighting quality (global illumination, raytracing, soft shadows), and artistic style (architectural photography, high-end visualization).

            Return the result in JSON format.`
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          english: { type: Type.STRING, description: "Detailed prompt in English" },
          portuguese: { type: Type.STRING, description: "Detailed prompt in Portuguese" },
          tags: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Relevant keywords for the visualization"
          }
        },
        required: ["english", "portuguese", "tags"]
      }
    }
  });

  const response = await model;
  return JSON.parse(response.text || '{}') as GeneratedPrompt;
};

import React, { useState, useRef, useCallback } from 'react';
import { 
  Camera, 
  Upload, 
  Sun, 
  CloudRain, 
  Moon, 
  Users, 
  Car, 
  MapPin, 
  Monitor, 
  Maximize, 
  Copy, 
  Check, 
  RefreshCw,
  Sparkles,
  ChevronRight
} from 'lucide-react';
import { PromptParameters, GeneratedPrompt, LightingMode, WeatherMode, StreetType, CameraAngle } from './types';
import { generateArchitecturalPrompt } from './geminiService';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<GeneratedPrompt | null>(null);
  const [copied, setCopied] = useState(false);

  const [params, setParams] = useState<PromptParameters>({
    lighting: 'afternoon',
    weather: 'sunny',
    peopleCount: 5,
    carCount: 2,
    streetType: 'with-sidewalk',
    cameraAngle: 'eye-level',
    environment: 'Urban context with landscaping'
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleCaptureScreen = async () => {
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({ video: true });
      const video = document.createElement('video');
      video.srcObject = stream;
      video.play();

      video.onloadedmetadata = () => {
        setTimeout(() => {
          const canvas = document.createElement('canvas');
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          const ctx = canvas.getContext('2d');
          ctx?.drawImage(video, 0, 0);
          const dataUrl = canvas.toDataURL('image/jpeg');
          setImage(dataUrl);

          // Stop all tracks
          stream.getTracks().forEach(track => track.stop());
        }, 500);
      };
    } catch (err) {
      console.error("Error capturing screen:", err);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!image) return;
    setLoading(true);
    try {
      const data = await generateArchitecturalPrompt(image, params);
      setResult(data);
    } catch (err) {
      console.error("Error generating prompt:", err);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-zinc-950/80 backdrop-blur-md border-b border-zinc-800 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="bg-blue-600 p-1.5 rounded-lg">
            <Sparkles className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">ArchPrompt <span className="text-blue-500">Pro</span></h1>
        </div>
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setImage(null)}
            className="text-sm text-zinc-400 hover:text-white transition-colors"
          >
            Limpar
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Image Area */}
        <div className="lg:col-span-7 space-y-6">
          <section className="bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden aspect-video relative group">
            {image ? (
              <img src={image} alt="Projeto" className="w-full h-full object-cover" />
            ) : (
              <div className="w-full h-full flex flex-col items-center justify-center p-12 text-center">
                <div className="bg-zinc-800 p-4 rounded-full mb-4">
                  <Camera className="w-8 h-8 text-zinc-400" />
                </div>
                <h3 className="text-lg font-medium mb-2">Seu projeto aqui</h3>
                <p className="text-zinc-500 text-sm max-w-xs mb-8">
                  Tire um print da sua tela de trabalho ou faça upload de uma imagem do seu projeto.
                </p>
                <div className="flex flex-wrap justify-center gap-4">
                  <button 
                    onClick={handleCaptureScreen}
                    className="flex items-center gap-2 bg-white text-zinc-950 px-5 py-2.5 rounded-xl font-semibold hover:bg-zinc-200 transition-all"
                  >
                    <Monitor className="w-4 h-4" />
                    Print da Tela
                  </button>
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="flex items-center gap-2 bg-zinc-800 text-white px-5 py-2.5 rounded-xl font-semibold hover:bg-zinc-700 transition-all border border-zinc-700"
                  >
                    <Upload className="w-4 h-4" />
                    Upload Arquivo
                  </button>
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="image/*" 
                    onChange={handleFileUpload} 
                  />
                </div>
              </div>
            )}

            {image && (
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4">
                <button 
                  onClick={handleCaptureScreen}
                  className="bg-white/10 backdrop-blur-md text-white p-3 rounded-full hover:bg-white/20 transition-all"
                  title="Capturar novo print"
                >
                  <RefreshCw className="w-5 h-5" />
                </button>
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="bg-white/10 backdrop-blur-md text-white p-3 rounded-full hover:bg-white/20 transition-all"
                  title="Upload novo arquivo"
                >
                  <Upload className="w-5 h-5" />
                </button>
              </div>
            )}
          </section>

          {/* Result Area */}
          {result && (
            <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6 space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center justify-between">
                <h2 className="text-lg font-semibold flex items-center gap-2">
                  <Sparkles className="w-5 h-5 text-blue-500" />
                  Prompt Gerado
                </h2>
                <div className="flex gap-2">
                  {result.tags.map((tag, i) => (
                    <span key={i} className="text-xs px-2 py-1 bg-zinc-800 rounded-md text-zinc-400">
                      #{tag}
                    </span>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <div className="relative group">
                  <div className="absolute top-4 right-4 flex gap-2">
                    <button 
                      onClick={() => copyToClipboard(result.english)}
                      className="p-2 bg-zinc-800/80 rounded-lg hover:bg-zinc-700 transition-all"
                      title="Copiar prompt em Inglês"
                    >
                      {copied ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                    </button>
                  </div>
                  <p className="text-xs font-bold text-zinc-500 uppercase mb-2">English (Recommended for Midjourney/SD)</p>
                  <div className="p-4 bg-zinc-950 border border-zinc-800 rounded-xl text-zinc-300 text-sm leading-relaxed min-h-[100px]">
                    {result.english}
                  </div>
                </div>

                <div className="relative group">
                  <p className="text-xs font-bold text-zinc-500 uppercase mb-2">Português</p>
                  <div className="p-4 bg-zinc-950 border border-zinc-800 rounded-xl text-zinc-300 text-sm leading-relaxed italic">
                    {result.portuguese}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Right Column: Controls */}
        <div className="lg:col-span-5 space-y-6">
          <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6 space-y-8 sticky top-24">
            <div>
              <h2 className="text-lg font-semibold mb-6 flex items-center gap-2">
                Parâmetros da Cena
              </h2>

              <div className="space-y-6">
                {/* Lighting */}
                <div className="space-y-3">
                  <label className="text-xs font-medium text-zinc-400 uppercase flex items-center gap-1.5">
                    <Sun className="w-3 h-3" /> Iluminação & Horário
                  </label>
                  <div className="grid grid-cols-4 gap-2">
                    {(['morning', 'afternoon', 'sunset', 'night'] as LightingMode[]).map((mode) => (
                      <button
                        key={mode}
                        onClick={() => setParams({...params, lighting: mode})}
                        className={`py-2 px-1 text-[10px] rounded-lg border transition-all flex flex-col items-center gap-1 capitalize ${
