                  <div className="grid grid-cols-2 gap-2">
                    {(['sunny', 'cloudy', 'rainy', 'post-rain'] as WeatherMode[]).map((mode) => (
                      <button
                        key={mode}
                        onClick={() => setParams({...params, weather: mode})}
                        className={`py-2 px-3 rounded-lg border transition-all text-sm capitalize ${
                          params.weather === mode 
