                        }`}
                      >
                        {mode === 'sunny' ? 'Dia de Sol' : mode === 'cloudy' ? 'Nublado' : mode === 'rainy' ? 'Chuvoso' : 'Pós-Chuva (Piso Molhado)'}
                      </button>
                    ))}
                  </div>
                </div>

