                    Ambiente Adicional
                  </label>
                  <textarea 
                    value={params.environment}
                    onChange={(e) => setParams({...params, environment: e.target.value})}
                    placeholder="Ex: Árvores de cerejeira, montanhas ao fundo, contexto urbano denso..."
                    className="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-2 text-sm text-zinc-200 outline-none focus:ring-1 ring-blue-500 min-h-[80px] resize-none"
                  />
                </div>
              </div>
            </div>

            <button
              onClick={handleGenerate}
              disabled={!image || loading}
              className={`w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center gap-2 transition-all shadow-lg ${
                !image 
                  ? 'bg-zinc-800 text-zinc-500 cursor-not-allowed border border-zinc-700' 
