                </>
              )}
            </button>
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-zinc-950 border-t border-zinc-900 py-8 px-6 mt-12">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4 text-zinc-500 text-sm">
          <p>© 2024 ArchPrompt Pro - Especializado em Render AI.</p>
          <div className="flex gap-6">
            <a href="#" className="hover:text-zinc-300">Documentação</a>
            <a href="#" className="hover:text-zinc-300">Suporte</a>
            <a href="#" className="hover:text-zinc-300">Privacidade</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

