                      className="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-2 text-[11px] text-zinc-200 outline-none focus:ring-1 ring-blue-500"
                    >
                      <option value="eye-level">Nível do Olho</option>
