                </div>

                <div className="space-y-4">
                  <div className="space-y-2">
                    <div className="flex justify-between items-center">
                      <label className="text-xs font-medium text-zinc-400 uppercase flex items-center gap-1.5">
                        <Users className="w-3 h-3" /> Pessoas
                      </label>
                      <span className="text-[10px] text-blue-400 font-bold">{params.peopleCount === 0 ? 'Nenhuma' : params.peopleCount > 15 ? 'Multidão' : params.peopleCount}</span>
                    </div>
                    <input 
                      type="range" min="0" max="20" step="1" 
                      value={params.peopleCount}
