};

export default App;

export type LightingMode = 'morning' | 'afternoon' | 'sunset' | 'night';
export type WeatherMode = 'sunny' | 'cloudy' | 'rainy' | 'post-rain';
export type StreetType = 'with-sidewalk' | 'no-sidewalk';
export type CameraAngle = 'eye-level' | 'wide' | 'close-up' | 'drone';
export type EnvironmentType = 'urban' | 'residential' | 'commercial' | 'industrial' | 'nature' | 'coastal' | 'others';

export interface PromptParameters {
  lighting: LightingMode;
  weather: WeatherMode;
  peopleCount: number;
  carCount: number;
  streetType: StreetType;
  cameraAngle: CameraAngle;
  environmentType: EnvironmentType;
  environmentDetails: string;
}

export interface GeneratedPrompt {
  english: string;
  portuguese: string;
  tags: string[];
}

import React, { useState, useRef } from 'react';
import { 
  Camera, 
  Upload, 
  Sun, 
  CloudRain, 
  Moon, 
  Users, 
  Car, 
  MapPin, 
  Monitor, 
  Maximize, 
  Copy, 
  Check, 
  RefreshCw,
  Sparkles,
  Building2,
  Home,
  Trees,
  Plus,
  Store,
  Factory,
  Waves
} from 'lucide-react';
import { PromptParameters, GeneratedPrompt, LightingMode, WeatherMode, StreetType, CameraAngle, EnvironmentType } from './types';
import { generateArchitecturalPrompt } from './geminiService';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<GeneratedPrompt | null>(null);
  const [copied, setCopied] = useState(false);

  const [params, setParams] = useState<PromptParameters>({
    lighting: 'afternoon',
    weather: 'sunny',
    peopleCount: 5,
    carCount: 2,
    streetType: 'with-sidewalk',
    cameraAngle: 'eye-level',
    environmentType: 'urban',
    environmentDetails: ''
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleCaptureScreen = async () => {
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({ video: true });
      const video = document.createElement('video');
      video.srcObject = stream;
      video.play();

      video.onloadedmetadata = () => {
        setTimeout(() => {
          const canvas = document.createElement('canvas');
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          const ctx = canvas.getContext('2d');
          ctx?.drawImage(video, 0, 0);
          const dataUrl = canvas.toDataURL('image/jpeg');
          setImage(dataUrl);

          stream.getTracks().forEach(track => track.stop());
        }, 500);
      };
    } catch (err) {
      console.error("Error capturing screen:", err);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!image) return;
    setLoading(true);
    try {
      const data = await generateArchitecturalPrompt(image, params);
      setResult(data);
    } catch (err) {
      console.error("Error generating prompt:", err);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const envOptions: { value: EnvironmentType; label: string; icon: React.ReactNode }[] = [
    { value: 'urban', label: 'Urbano', icon: <Building2 className="w-4 h-4" /> },
    { value: 'residential', label: 'Residencial', icon: <Home className="w-4 h-4" /> },
    { value: 'commercial', label: 'Comercial', icon: <Store className="w-4 h-4" /> },
    { value: 'industrial', label: 'Industrial', icon: <Factory className="w-4 h-4" /> },
    { value: 'nature', label: 'Natureza', icon: <Trees className="w-4 h-4" /> },
    { value: 'coastal', label: 'Litoral', icon: <Waves className="w-4 h-4" /> },
    { value: 'others', label: 'Outros', icon: <Plus className="w-4 h-4" /> },
  ];

  return (
    <div className="min-h-screen flex flex-col">
      <header className="sticky top-0 z-50 bg-zinc-950/80 backdrop-blur-md border-b border-zinc-800 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="bg-blue-600 p-1.5 rounded-lg shadow-lg shadow-blue-500/20">
            <Sparkles className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">ArchPrompt <span className="text-blue-500">Pro</span></h1>
        </div>
        <div className="flex items-center gap-4">
          <button 
            onClick={() => { setImage(null); setResult(null); }}
            className="text-sm text-zinc-400 hover:text-white transition-colors"
          >
            Limpar
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Visualização do Projeto */}
        <div className="lg:col-span-7 space-y-6">
          <section className="bg-zinc-900 border border-zinc-800 rounded-3xl overflow-hidden aspect-video relative group ring-1 ring-white/5">
            {image ? (
              <img src={image} alt="Projeto" className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" />
            ) : (
              <div className="w-full h-full flex flex-col items-center justify-center p-12 text-center">
                <div className="bg-zinc-800/50 p-6 rounded-full mb-6 ring-1 ring-zinc-700">
                  <Camera className="w-10 h-10 text-zinc-400" />
                </div>
                <h3 className="text-xl font-semibold mb-2">Seu projeto aqui</h3>
                <p className="text-zinc-500 text-sm max-w-xs mb-8 leading-relaxed">
                  Tire um print da sua tela de trabalho ou faça upload de uma imagem do seu projeto.
                </p>
                <div className="flex flex-wrap justify-center gap-4">
                  <button 
                    onClick={handleCaptureScreen}
                    className="flex items-center gap-2 bg-white text-zinc-950 px-6 py-3 rounded-2xl font-bold hover:bg-zinc-200 hover:-translate-y-0.5 active:translate-y-0 transition-all shadow-xl shadow-white/5"
                  >
                    <Monitor className="w-4 h-4" />
                    Print da Tela
                  </button>
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="flex items-center gap-2 bg-zinc-800 text-white px-6 py-3 rounded-2xl font-bold hover:bg-zinc-700 border border-zinc-700 transition-all shadow-lg"
                  >
                    <Upload className="w-4 h-4" />
                    Upload Arquivo
                  </button>
                  <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
                </div>
              </div>
            )}

            {image && (
              <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-all duration-300 flex items-center justify-center gap-4 backdrop-blur-[2px]">
                <button 
                  onClick={handleCaptureScreen}
                  className="bg-white/10 backdrop-blur-xl text-white p-4 rounded-2xl hover:bg-white/20 transition-all border border-white/10 hover:scale-110"
                  title="Capturar novo print"
                >
                  <RefreshCw className="w-6 h-6" />
                </button>
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="bg-white/10 backdrop-blur-xl text-white p-4 rounded-2xl hover:bg-white/20 transition-all border border-white/10 hover:scale-110"
                  title="Upload novo arquivo"
                >
                  <Upload className="w-6 h-6" />
                </button>
              </div>
            )}
          </section>

          {/* Resultado do Prompt */}
          {result && (
            <div className="bg-zinc-900 border border-zinc-800 rounded-3xl p-8 space-y-6 animate-in fade-in slide-in-from-bottom-6 duration-700 shadow-2xl">
              <div className="flex items-center justify-between border-b border-zinc-800 pb-4">
                <h2 className="text-xl font-bold flex items-center gap-3">
                  <Sparkles className="w-6 h-6 text-blue-500" />
                  Prompt Profissional
                </h2>
                <div className="flex flex-wrap gap-2">
                  {result.tags.map((tag, i) => (
                    <span key={i} className="text-[10px] px-3 py-1 bg-blue-500/10 rounded-full text-blue-400 border border-blue-500/20 font-semibold uppercase tracking-wider">
                      {tag}
                    </span>
                  ))}
                </div>
              </div>

              <div className="space-y-6">
                <div className="relative group">
                  <div className="absolute top-4 right-4 flex gap-2">
                    <button 
                      onClick={() => copyToClipboard(result.english)}
                      className="p-3 bg-blue-600 rounded-xl hover:bg-blue-500 transition-all shadow-lg shadow-blue-500/30 flex items-center gap-2 group/btn"
                    >
                      {copied ? <Check className="w-4 h-4 text-white" /> : <Copy className="w-4 h-4 text-white" />}
                      <span className="text-xs font-bold text-white pr-1">COPIAR</span>
                    </button>
                  </div>
                  <p className="text-[11px] font-black text-zinc-500 uppercase tracking-[0.2em] mb-3">AI PROMPT ENGINE (ENGLISH)</p>
                  <div className="p-6 bg-zinc-950/50 border border-zinc-800 rounded-2xl text-zinc-200 text-sm leading-relaxed min-h-[140px] whitespace-pre-wrap font-mono selection:bg-blue-500/30">
                    {result.english}
                  </div>
                </div>

                <div className="relative group">
                  <p className="text-[11px] font-black text-zinc-500 uppercase tracking-[0.2em] mb-3">Tradução Contextual (Português)</p>
                  <div className="p-6 bg-zinc-900/50 border border-zinc-800 rounded-2xl text-zinc-400 text-sm leading-relaxed italic">
                    {result.portuguese}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Coluna de Controles */}
        <div className="lg:col-span-5 space-y-6">
          <div className="bg-zinc-900 border border-zinc-800 rounded-3xl p-8 space-y-8 sticky top-24 shadow-xl ring-1 ring-white/5">
            <div>
