import { GoogleGenAI, Type } from "@google/genai";
import { PromptParameters, GeneratedPrompt } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateArchitecturalPrompt = async (
  imageData: string,
  params: PromptParameters
): Promise<GeneratedPrompt> => {
  const model = ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: imageData.split(',')[1],
            },
          },
          {
            text: `Analyze this architectural project image and generate a highly professional, detailed prompt for high-end AI image generators (Midjourney v6, Stable Diffusion XL, or DALL-E 3).

            USER SPECIFICATIONS:
            - Lighting Condition: ${params.lighting}
            - Weather/Atmosphere: ${params.weather}
            - Human Presence: ${params.peopleCount} people in scene
            - Vehicle Traffic: ${params.carCount} cars nearby
            - Street Configuration: ${params.streetType}
            - Camera Perspective: ${params.cameraAngle}
            - Environment Category: ${params.environmentType}
            - Additional Architectural Details: ${params.environmentDetails}

            INSTRUCTIONS:
            1. Describe the materials (concrete, glass, wood, metal) based on the image provided.
            2. Apply the chosen environment (${params.environmentType}). For example, if 'coastal', add seaside elements; if 'industrial', add raw textures and factory backgrounds.
            3. Set the lighting to ${params.lighting} style (e.g., golden hour for sunset, cool tones for night).
            4. If weather is 'post-rain', emphasize wet pavement reflections and puddles.
            5. Style: Professional architectural photography, photorealistic, 8k, highly detailed, architectural visualization, raytraced, V-Ray style.

            Return the result in JSON format.`
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          english: { type: Type.STRING, description: "Detailed AI prompt in English" },
          portuguese: { type: Type.STRING, description: "Detailed explanation in Portuguese" },
          tags: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Technical keywords for rendering settings"
          }
        },
        required: ["english", "portuguese", "tags"]
      }
    }
  });

  const response = await model;
  return JSON.parse(response.text || '{}') as GeneratedPrompt;
};

export type LightingMode = 'Manhã' | 'Tarde' | 'Fim de Tarde' | 'Noturno';
export type WeatherMode = 'Dia de Sol' | 'Nublado' | 'Chuvoso' | 'Pós-Chuva';
export type Level = 'Nenhum' | 'Poucos' | 'Médio' | 'Muitos';
export type SocialFormat = 'Instagram / TikTok (9:16)' | 'YouTube / TV (16:9)' | 'Post / Feed (1:1)' | 'Cinematográfico (2.35:1)';
export type VisualStyle = 'Hiper-realista' | 'V-Ray Render' | 'Unreal Engine 5' | 'Sketch / Croqui' | 'Maquete Eletrônica';
export type CameraAngle = 'Nível do Olhar' | 'Grande Angular' | 'Close-up' | 'Drone / Aéreo';
export type EnvironmentType = 'Comercial/Urbano' | 'Residencial' | 'Industrial' | 'Litoral' | 'Natureza';

export interface PromptParameters {
  socialFormat: SocialFormat;
  visualStyle: VisualStyle;
  environmentType: EnvironmentType;
  cameraAngle: CameraAngle;
  lighting: LightingMode;
  weather: WeatherMode;
  peopleLevel: Level;
  carLevel: Level;
  environmentDetails: string;
}

export interface GeneratedPrompt {
  english: string;
  portuguese: string;
  tags: string[];
}

