export type LightingMode = 'Manhã' | 'Tarde' | 'Fim de Tarde' | 'Noturno';
export type WeatherMode = 'Dia de Sol' | 'Nublado' | 'Chuvoso' | 'Pós-Chuva';
export type SocialFormat = 'Instagram / TikTok (9:16)' | 'YouTube / TV (16:9)' | 'Post / Feed (1:1)' | 'Cinematográfico (2.35:1)';
export type VisualStyle = 'Hiper-realista' | 'V-Ray Render' | 'Unreal Engine 5' | 'Sketch / Croqui' | 'Maquete Eletrônica';
export type CameraAngle = 'Nível do Olhar' | 'Grande Angular' | 'Close-up' | 'Drone / Aéreo';
export type EnvironmentType = 'Comercial/Urbano' | 'Residencial' | 'Industrial' | 'Litoral' | 'Natureza';

export interface PromptParameters {
  socialFormat: SocialFormat;
  visualStyle: VisualStyle;
  environmentType: EnvironmentType;
  cameraAngle: CameraAngle;
  lighting: LightingMode;
  weather: WeatherMode;
  peopleCount: number;
  carCount: number;
  environmentDetails: string;
}

export interface GeneratedPrompt {
  english: string;
  portuguese: string;
  tags: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { PromptParameters, GeneratedPrompt } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateArchitecturalPrompt = async (
  imageData: string,
  params: PromptParameters
): Promise<GeneratedPrompt> => {
  const model = ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: imageData.split(',')[1],
            },
          },
          {
            text: `Atue como um especialista em visualização arquitetônica. Analise a imagem e crie um prompt profissional para Midjourney/Stable Diffusion.

            ESPECIFICAÇÕES DO USUÁRIO:
            - Formato Social: ${params.socialFormat}
            - Estilo Visual: ${params.visualStyle}
            - Contexto: ${params.environmentType}
            - Ângulo: ${params.cameraAngle}
            - Iluminação: ${params.lighting}
            - Clima: ${params.weather}
            - Quantidade de Pessoas: ${params.peopleCount}
            - Quantidade de Carros: ${params.carCount}
            - Detalhes Extras: ${params.environmentDetails}

            INSTRUÇÕES:
            1. Descreva materiais, texturas e reflexos baseados na imagem e no estilo ${params.visualStyle}.
            2. O prompt deve ser em inglês, ultra-detalhado, focando em iluminação global, raytracing e realismo.
            3. Adicione parâmetros técnicos de renderização ao final.

            Retorne em JSON.`
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          english: { type: Type.STRING },
          portuguese: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["english", "portuguese", "tags"]
      }
    }
  });

  const response = await model;
  return JSON.parse(response.text || '{}') as GeneratedPrompt;
};

