import { GoogleGenAI, Type } from "@google/genai";
import { PromptParameters, GeneratedPrompt } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateArchitecturalPrompt = async (
  imageData: string,
  params: PromptParameters
): Promise<GeneratedPrompt> => {
  const model = ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: imageData.split(',')[1],
            },
          },
          {
            text: `Você é um diretor de arte especializado em ArchViz (Visualização Arquitetônica).
            Sua missão é criar o prompt definitivo para IAs de imagem de alta performance (Midjourney v6.1 ou superior).

            ESPECIFICAÇÕES TÉCNICAS DO USUÁRIO:
            - Proporção/Formato: ${params.socialFormat}
            - Estética de Render: ${params.visualStyle}
            - Localização do Entorno: ${params.environmentType}
            - Enquadramento de Câmera: ${params.cameraAngle}
            - Iluminação: ${params.lighting}
            - Condições Meteorológicas: ${params.weather}
            - Densidade Populacional: ${params.peopleCount} pessoas no frame
            - Densidade de Tráfego: ${params.carCount} veículos
            - Notas de Materiais e Fachada: ${params.environmentDetails}

            ESTRUTURA DO PROMPT ESPERADO:
            1. Definição do Sujeito: Descreva a arquitetura baseada na imagem, focando em materiais nobres como ACM, concreto ripado, esquadrias minimalistas e peles de vidro.
            2. Atmosfera e Luz: Capture a essência da iluminação ${params.lighting}, enfatizando reflexos HDR, cáusticas em superfícies molhadas (se aplicável) e sombras suaves.
            3. Contexto: Insira a edificação no ambiente ${params.environmentType} com os detalhes específicos de ${params.environmentDetails}.
            4. Especificações de Câmera: Use termos de fotografia profissional (f/1.8, ISO 100, 35mm lens) e estilos de renderização (Octane Render, Unreal Engine 5, Lumen, Photorealistic).

            Return the output in JSON format with 'english' (the full prompt), 'portuguese' (a technical summary) and 'tags' (metadata keywords).`
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          english: { type: Type.STRING },
          portuguese: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["english", "portuguese", "tags"]
      }
    }
  });

  const response = await model;
  return JSON.parse(response.text || '{}') as GeneratedPrompt;
};

