import React, { useState, useRef, useEffect } from 'react';
import { 
  Camera, Upload, Sun, CloudRain, Moon, Users, Car, MapPin, 
  Monitor, Maximize, Copy, Check, RefreshCw, Sparkles, 
  Smartphone, Palette, Building2, Focus, ChevronDown, Zap,
  Layers, Globe, Layout, Send, Wind, Droplets
} from 'lucide-react';
import { 
  PromptParameters, GeneratedPrompt, LightingMode, WeatherMode, 
  SocialFormat, VisualStyle, CameraAngle, EnvironmentType 
} from './types';
import { generateArchitecturalPrompt } from './geminiService';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<GeneratedPrompt | null>(null);
  const [copied, setCopied] = useState(false);

  const [params, setParams] = useState<PromptParameters>({
    socialFormat: 'Instagram / TikTok (9:16)',
    visualStyle: 'Hiper-realista',
    environmentType: 'Comercial/Urbano',
    cameraAngle: 'Nível do Olhar',
    lighting: 'Noturno',
    weather: 'Dia de Sol',
    peopleCount: 5,
    carCount: 2,
    environmentDetails: ''
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleCaptureScreen = async () => {
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({ video: true });
      const video = document.createElement('video');
      video.srcObject = stream;
      video.play();
      video.onloadedmetadata = () => {
        setTimeout(() => {
          const canvas = document.createElement('canvas');
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          canvas.getContext('2d')?.drawImage(video, 0, 0);
          setImage(canvas.toDataURL('image/jpeg'));
          stream.getTracks().forEach(t => t.stop());
        }, 500);
      };
    } catch (err) { console.error(err); }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const addDetail = (text: string) => {
    setParams(p => ({
      ...p,
      environmentDetails: p.environmentDetails ? `${p.environmentDetails}, ${text}` : text
    }));
  };

  const SelectField = ({ icon: Icon, label, value, options, onChange }: any) => (
    <div className="space-y-3 group/field">
      <div className="flex items-center gap-2.5 text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] group-hover/field:text-fuchsia-400 transition-colors">
        <Icon className="w-3.5 h-3.5" />
        {label}
      </div>
      <div className="relative">
        <select 
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="w-full bg-zinc-900/40 border border-white/5 rounded-2xl px-5 py-3.5 text-sm text-zinc-200 outline-none focus:border-fuchsia-500/50 focus:ring-4 focus:ring-fuchsia-500/10 appearance-none cursor-pointer pr-12 transition-all hover:bg-zinc-900/60"
        >
          {options.map((opt: string) => <option key={opt} value={opt} className="bg-zinc-900">{opt}</option>)}
        </select>
        <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-zinc-500">
          <ChevronDown className="w-4 h-4" />
        </div>
      </div>
    </div>
  );

  const SliderField = ({ icon: Icon, label, value, min, max, onChange }: any) => {
    const getStatus = (v: number) => {
      if (v === 0) return 'Vazio';
      if (v < 5) return 'Mínimo';
      if (v < 15) return 'Médio';
      return 'Denso';
    };

    return (
      <div className="space-y-4 group/field">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2.5 text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] group-hover/field:text-fuchsia-400 transition-colors">
            <Icon className="w-3.5 h-3.5" />
            {label}
          </div>
          <div className="flex items-center gap-2">
            <span className="text-[10px] font-bold text-zinc-400 bg-zinc-800/50 px-2 py-0.5 rounded border border-white/5 uppercase tracking-tighter">
              {getStatus(value)}
            </span>
            <span className="text-xs font-black text-fuchsia-500 tabular-nums">
              {value}
            </span>
          </div>
        </div>
        <div className="relative flex items-center h-6">
          <input 
            type="range" 
            min={min} 
            max={max} 
            value={value}
            onChange={(e) => onChange(parseInt(e.target.value))}
            className="w-full h-1 bg-zinc-800 rounded-full appearance-none cursor-pointer accent-fuchsia-500 hover:accent-fuchsia-400 transition-all"
          />
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#050505] text-zinc-200 flex flex-col relative overflow-hidden selection:bg-fuchsia-500/30 selection:text-white">

      <div className="fixed top-[-10%] left-[-10%] w-[40%] h-[40%] bg-fuchsia-600/10 blur-[150px] pointer-events-none rounded-full" />
      <div className="fixed bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[150px] pointer-events-none rounded-full" />

      <header className="sticky top-0 z-50 glass-panel border-b border-white/5 px-10 py-5 flex items-center justify-between">
        <div className="flex items-center gap-5">
          <div className="relative group">
            <div className="absolute inset-0 bg-fuchsia-500 blur-lg opacity-20 group-hover:opacity-40 transition-opacity" />
            <div className="relative bg-gradient-to-br from-fuchsia-500 to-purple-700 p-2.5 rounded-2xl shadow-2xl shadow-fuchsia-500/30">
              <Sparkles className="w-6 h-6 text-white" />
            </div>
          </div>
          <div className="flex flex-col -space-y-1">
            <h1 className="text-2xl font-black tracking-tighter text-white uppercase italic">
              FCD <span className="text-fuchsia-500">VIEW</span>PROMPT
            </h1>
            <p className="text-[9px] font-black text-zinc-500 uppercase tracking-[0.4em]">Laboratório Avançado de ArchViz</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <nav className="hidden md:flex items-center gap-8 mr-12 text-[10px] font-black uppercase tracking-widest text-zinc-500">
            <a href="#" className="hover:text-fuchsia-400 transition-colors">Explorar</a>
            <a href="#" className="hover:text-fuchsia-400 transition-colors">Ativos</a>
            <a href="#" className="hover:text-fuchsia-400 transition-colors">Nuvem</a>
          </nav>
          {image && (
            <button 
              onClick={() => { setImage(null); setResult(null); }} 
              className="group flex items-center gap-2 text-[10px] font-black text-zinc-500 hover:text-white uppercase tracking-widest transition-all"
            >
              <RefreshCw className="w-3.5 h-3.5 group-hover:rotate-180 transition-transform duration-500" />
