            </button>
          )}
        </div>
      </header>

      <main className="flex-1 max-w-[1600px] mx-auto w-full p-10 grid grid-cols-1 lg:grid-cols-12 gap-12 items-start">

        <div className="lg:col-span-8 space-y-12">
          <div className="relative group rounded-[40px] overflow-hidden bg-zinc-900/40 border border-white/5 shadow-[0_0_100px_rgba(0,0,0,0.5)] aspect-video">
            {image ? (
