import { GoogleGenAI, Type } from "@google/genai";
import { PromptParameters, GeneratedPrompt } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateArchitecturalPrompt = async (
  imageData: string,
  params: PromptParameters
): Promise<GeneratedPrompt> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "image/jpeg",
            data: imageData.split(',')[1],
          },
        },
        {
          text: `Você é um diretor de arte especializado em ArchViz. Analise a imagem e crie um prompt mestre.

            PARÂMETROS:
            - Formato: ${params.socialFormat}
            - Estética: ${params.visualStyle}
            - Contexto: ${params.environmentType}
            - Câmera: ${params.cameraAngle}
            - Luz: ${params.lighting}
            - Clima: ${params.weather}
            - População: ${params.peopleCount} pessoas
            - Veículos: ${params.carCount} carros
            - Detalhes Extras: ${params.environmentDetails}

            Gere um JSON com:
            1. 'english': Prompt técnico e artístico detalhado em inglês para Midjourney v6.1. Inclua parâmetros como --ar e detalhes de iluminação global.
            2. 'portuguese': Resumo técnico da análise arquitetônica.
            3. 'tags': 5 palavras-chave.

            Importante: Foque em materiais realistas e iluminação volumétrica.`
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          english: { type: Type.STRING },
          portuguese: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["english", "portuguese", "tags"]
      }
    }
  });

  const data = JSON.parse(response.text || '{}');
  return {
    ...data,
    id: Math.random().toString(36).substr(2, 9),
    timestamp: Date.now()
  };
};

export const generateSamplePreview = async (prompt: string, aspectRatio: string): Promise<string> => {
  const ratioMap: Record<string, "1:1" | "4:3" | "3:4" | "16:9" | "9:16"> = {
    'Instagram / TikTok (9:16)': "9:16",
    'YouTube / TV (16:9)': "16:9",
    'Post / Feed (1:1)': "1:1",
    'Cinematográfico (2.35:1)': "16:9" // Fallback pois 2.35 não é nativo
  };

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `High quality architectural visualization render: ${prompt}` }],
    },
    config: {
      imageConfig: {
        aspectRatio: ratioMap[aspectRatio] || "1:1"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Falha ao gerar preview");
};

