import { GoogleGenAI, Type } from "@google/genai";
import { PromptParameters, GeneratedPrompt } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateArchitecturalPrompt = async (
  imageData: string,
  params: PromptParameters
): Promise<GeneratedPrompt> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "image/jpeg",
            data: imageData.split(',')[1],
          },
        },
        {
          text: `Você é um diretor de arte especializado em ArchViz. Analise a imagem e crie um prompt mestre.

            PARÂMETROS:
            - Formato (Aspect Ratio): ${params.socialFormat}
            - Estética: ${params.visualStyle}
            - Contexto: ${params.environmentType}
            - Câmera: ${params.cameraAngle}
            - Luz: ${params.lighting}
            - Clima: ${params.weather}
            - População: ${params.peopleCount} pessoas
            - Veículos: ${params.carCount} carros
            - Detalhes Extras: ${params.environmentDetails}
            - Letreiro Iluminado: ${params.illuminatedSignage ? "Ativado (Efeito halo/backlit mantendo a cor original da face das letras)" : "Desativado"}

            Gere um JSON com:
            1. 'english': Prompt técnico e artístico detalhado em inglês para Midjourney v6.1. Se o letreiro iluminado estiver ativado, use termos como "halo-lit signage", "backlit channel letters" ou "edge-lit signage" enfatizando que a face frontal mantém sua cor sólida.
            2. 'portuguese': Resumo técnico da análise arquitetônica.
            3. 'tags': 5 palavras-chave.

            Importante: Foque em materiais realistas e iluminação volumétrica.`
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          english: { type: Type.STRING },
          portuguese: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["english", "portuguese", "tags"]
      }
    }
  });

  const data = JSON.parse(response.text || '{}');
  return {
    ...data,
    id: Math.random().toString(36).substr(2, 9),
    timestamp: Date.now()
  };
};

export const generateSamplePreview = async (prompt: string, aspectRatio: string): Promise<string> => {
  const ratioMap: Record<string, "1:1" | "3:4" | "4:3" | "9:16" | "16:9"> = {
    'Instagram / TikTok (9:16)': "9:16",
    'Instagram Portrait (4:5)': "3:4",
    'Post / Feed (1:1)': "1:1",
    'YouTube / TV (16:9)': "16:9",
    'Fotografia (3:2)': "4:3",
    'Cinematográfico (2.35:1)': "16:9",
    'Vertical Clássico (2:3)': "3:4"
  };

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `Professional high quality architectural visualization render: ${prompt}` }],
    },
    config: {
      imageConfig: {
        aspectRatio: ratioMap[aspectRatio] || "1:1"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Falha ao gerar preview");
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  Upload, Sun, Copy, Check, RefreshCw, Sparkles, 
  Palette, Focus, ChevronDown, Zap,
  Globe, Layout, Send, Users, Car, History, Eye, Trash2, Download, Lightbulb
} from 'lucide-react';
import { 
  PromptParameters, GeneratedPrompt, LightingMode, WeatherMode 
} from './types';
import { generateArchitecturalPrompt, generateSamplePreview } from './geminiService';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [previewLoading, setPreviewLoading] = useState(false);
  const [result, setResult] = useState<GeneratedPrompt | null>(null);
  const [history, setHistory] = useState<GeneratedPrompt[]>([]);
  const [copied, setCopied] = useState(false);
  const [isDragging, setIsDragging] = useState(false);

  const [params, setParams] = useState<PromptParameters>({
    socialFormat: 'Instagram / TikTok (9:16)',
    visualStyle: 'Hiper-realista',
    environmentType: 'Comercial/Urbano',
    cameraAngle: 'Nível do Olhar',
    lighting: 'Noturno',
    weather: 'Dia de Sol',
    peopleCount: 5,
    carCount: 2,
    environmentDetails: '',
    illuminatedSignage: false
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('fcd_history');
    if (saved) setHistory(JSON.parse(saved));
  }, []);

  const saveToHistory = (item: GeneratedPrompt) => {
    const newHistory = [item, ...history].slice(0, 5);
    setHistory(newHistory);
    localStorage.setItem('fcd_history', JSON.stringify(newHistory));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement> | React.DragEvent) => {
    let file: File | undefined;
    if ('files' in e) {
      file = (e.target as HTMLInputElement).files?.[0];
    } else {
      e.preventDefault();
      file = e.dataTransfer.files?.[0];
      setIsDragging(false);
    }

    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const generatePreview = async () => {
    if (!result || previewLoading) return;
    setPreviewLoading(true);
    try {
      const url = await generateSamplePreview(result.english, params.socialFormat);
      const updatedResult = { ...result, previewUrl: url };
      setResult(updatedResult);
      const newHistory = history.map(h => h.id === result.id ? updatedResult : h);
      setHistory(newHistory);
      localStorage.setItem('fcd_history', JSON.stringify(newHistory));
    } catch (err) {
      console.error(err);
    } finally {
      setPreviewLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const SelectField = ({ icon: Icon, label, value, options, onChange }: any) => (
    <div className="space-y-3 group/field">
      <div className="flex items-center gap-2.5 text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] group-hover/field:text-fuchsia-400 transition-colors">
        <Icon className="w-3.5 h-3.5" />
        {label}
      </div>
      <div className="relative">
        <select 
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="w-full bg-zinc-900/40 border border-white/5 rounded-2xl px-5 py-3.5 text-sm text-zinc-200 outline-none focus:border-fuchsia-500/50 focus:ring-4 focus:ring-fuchsia-500/10 appearance-none cursor-pointer pr-12 transition-all hover:bg-zinc-900/60"
        >
          {options.map((opt: string) => <option key={opt} value={opt} className="bg-zinc-900">{opt}</option>)}
        </select>
        <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 pointer-events-none text-zinc-500" />
      </div>
    </div>
  );

  const SliderField = ({ icon: Icon, label, value, min, max, onChange }: any) => (
    <div className="space-y-4 group/field">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-2.5 text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] group-hover/field:text-fuchsia-400 transition-colors">
          <Icon className="w-3.5 h-3.5" />
          {label}
        </div>
        <span className="text-xs font-black text-fuchsia-500 tabular-nums">{value}</span>
      </div>
      <input 
        type="range" min={min} max={max} value={value}
        onChange={(e) => onChange(parseInt(e.target.value))}
        className="w-full h-1 bg-zinc-800 rounded-full appearance-none cursor-pointer accent-fuchsia-500"
      />
    </div>
  );

  return (
    <div className="min-h-screen bg-[#050505] text-zinc-200 flex flex-col relative overflow-hidden">

      <div className="fixed top-[-10%] left-[-10%] w-[40%] h-[40%] bg-fuchsia-600/10 blur-[150px] pointer-events-none" />
      <div className="fixed bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[150px] pointer-events-none" />

      <header className="sticky top-0 z-50 glass-panel border-b border-white/5 px-10 py-5 flex items-center justify-between">
        <div className="flex items-center gap-5">
          <div className="relative group">
            <div className="absolute inset-0 bg-fuchsia-500 blur-lg opacity-20" />
            <div className="relative bg-gradient-to-br from-fuchsia-500 to-purple-700 p-2.5 rounded-2xl">
              <Sparkles className="w-6 h-6 text-white" />
            </div>
          </div>
          <h1 className="text-2xl font-black tracking-tighter text-white uppercase italic">
            FCD <span className="text-fuchsia-500">VIEW</span>PROMPT
          </h1>
        </div>
        <div className="flex items-center gap-4">
          {image && (
            <button 
              onClick={() => { setImage(null); setResult(null); }} 
              className="text-[10px] font-black text-zinc-500 hover:text-white uppercase tracking-widest flex items-center gap-2"
            >
              <RefreshCw className="w-3 h-3" /> Resetar
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 max-w-[1600px] mx-auto w-full p-10 grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Lado Esquerdo: History (Desktop) */}
        <div className="hidden xl:block lg:col-span-1 space-y-4">
          <div className="flex flex-col items-center gap-6">
            <History className="w-5 h-5 text-zinc-600" />
            <div className="flex flex-col gap-4">
              {history.map(item => (
                <button 
                  key={item.id}
                  onClick={() => setResult(item)}
                  className={`w-12 h-12 rounded-xl border transition-all overflow-hidden ${result?.id === item.id ? 'border-fuchsia-500 scale-110 shadow-lg shadow-fuchsia-500/20' : 'border-white/5 opacity-40 hover:opacity-100'}`}
                >
                   <div className="w-full h-full bg-zinc-900 flex items-center justify-center text-[10px] font-bold">
                     #{item.id.slice(0, 3)}
                   </div>
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Central: Visualizer */}
        <div className="lg:col-span-11 xl:col-span-7 space-y-12">
          <div 
            onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
            onDragLeave={() => setIsDragging(false)}
            onDrop={handleFileUpload}
            className={`relative group rounded-[40px] overflow-hidden bg-zinc-900/40 border transition-all duration-500 aspect-video flex flex-col items-center justify-center ${isDragging ? 'border-fuchsia-500 bg-fuchsia-500/5 scale-[0.99]' : 'border-white/5'}`}
          >
            {image ? (
              <div className="w-full h-full relative group">
                <img src={image} className="w-full h-full object-cover" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-8">
                   <button onClick={() => fileInputRef.current?.click()} className="bg-white text-black px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest">Trocar Snapshot</button>
                </div>
                {loading && <div className="scan-line" />}
              </div>
            ) : (
              <div className="text-center p-12">
                <div className="bg-zinc-900 p-8 rounded-full inline-block mb-6 border border-white/5">
                  <Upload className={`w-12 h-12 ${isDragging ? 'text-fuchsia-500' : 'text-zinc-700'}`} />
                </div>
                <h3 className="text-2xl font-black mb-2 uppercase tracking-tighter">Arraste seu Render</h3>
                <p className="text-zinc-500 text-xs uppercase tracking-widest mb-8">Snapshot direto do seu software 3D</p>
                <button onClick={() => fileInputRef.current?.click()} className="bg-white text-black px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:scale-105 transition-all">Selecionar Arquivo</button>
              </div>
            )}
          </div>

          {result && (
            <div className="space-y-10 animate-in fade-in slide-in-from-bottom-8 duration-700">
              <div className="glass-panel rounded-[40px] p-10 space-y-8">
                <div className="flex items-center justify-between border-b border-white/5 pb-8">
                   <div className="flex items-center gap-4">
                     <div className="w-12 h-12 bg-fuchsia-500/10 rounded-2xl flex items-center justify-center">
                       <Zap className="w-6 h-6 text-fuchsia-400" />
                     </div>
                     <div>
                       <h2 className="text-xl font-black uppercase italic">AI Prompt Engine</h2>
                       <p className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest">Otimizado para Midjourney v6.1</p>
                     </div>
                   </div>
                   <button 
                    onClick={() => copyToClipboard(result.english)}
                    className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${copied ? 'bg-green-600' : 'bg-fuchsia-600 hover:bg-fuchsia-500'}`}
                  >
                    {copied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />} 
                    {copied ? 'Copiado' : 'Copiar Tudo'}
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-6">
                    <div>
                      <span className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] block mb-3">Prompt Estruturado</span>
                      <div className="bg-black/40 p-6 rounded-3xl border border-white/5 text-sm leading-relaxed text-zinc-300 min-h-[150px]">
                        {result.english}
                      </div>
                    </div>
                    <div>
                      <span className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] block mb-3">Tags de Laboratório</span>
                      <div className="flex flex-wrap gap-2">
                        {result.tags.map(t => <span key={t} className="bg-white/5 border border-white/5 px-3 py-1.5 rounded-lg text-[10px] font-bold text-zinc-400">#{t}</span>)}
                      </div>
                    </div>
                  </div>

                  <div className="space-y-6">
                    <span className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] block mb-3">Preview de Amostra (IA)</span>
                    <div className="relative aspect-square bg-zinc-900 rounded-3xl border border-white/5 overflow-hidden group">
                      {result.previewUrl ? (
                        <img src={result.previewUrl} className="w-full h-full object-cover" />
                      ) : (
                        <div className="w-full h-full flex flex-col items-center justify-center p-8 text-center">
                          <Eye className="w-8 h-8 text-zinc-700 mb-4" />
                          <p className="text-[10px] font-bold text-zinc-500 uppercase leading-relaxed">Gere uma prévia visual para testar a fidelidade do prompt</p>
                        </div>
                      )}

                      {previewLoading && (
                        <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center">
                          <RefreshCw className="w-8 h-8 animate-spin text-fuchsia-500" />
                        </div>
                      )}

                      {!result.previewUrl && !previewLoading && (
                        <button 
                          onClick={generatePreview}
                          className="absolute inset-0 flex items-center justify-center bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <span className="bg-white text-black px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest shadow-2xl">Gerar Preview</span>
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Direita: Controls */}
        <div className="lg:col-span-12 xl:col-span-4 sticky top-10">
          <div className="glass-panel rounded-[40px] p-8 space-y-8 shadow-2xl">
            <h2 className="text-[11px] font-black tracking-[0.4em] uppercase text-zinc-500 flex items-center gap-3">
               <div className="w-1.5 h-1.5 rounded-full bg-fuchsia-500 animate-pulse" />
               Controladores de Cena
            </h2>

            <div className="space-y-6 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
              <SelectField 
                icon={Layout} label="Aspect Ratio" value={params.socialFormat} 
                options={[
                  'Instagram / TikTok (9:16)', 
                  'Instagram Portrait (4:5)', 
                  'Post / Feed (1:1)', 
                  'YouTube / TV (16:9)', 
                  'Fotografia (3:2)', 
                  'Cinematográfico (2.35:1)', 
                  'Vertical Clássico (2:3)'
                ]}
                onChange={(v: any) => setParams({...params, socialFormat: v})}
              />
              <SelectField 
                icon={Palette} label="Engine Estética" value={params.visualStyle} 
                options={['Hiper-realista', 'V-Ray Render', 'Unreal Engine 5', 'Sketch / Croqui', 'Maquete Eletrônica']}
                onChange={(v: any) => setParams({...params, visualStyle: v})}
              />
              <div className="grid grid-cols-2 gap-4">
                 <SelectField 
                  icon={Sun} label="Luz" value={params.lighting} 
                  options={['Manhã', 'Tarde', 'Fim de Tarde', 'Noturno']}
                  onChange={(v: any) => setParams({...params, lighting: v})}
                />
                <SelectField 
                  icon={Globe} label="Clima" value={params.weather} 
                  options={['Dia de Sol', 'Nublado', 'Chuvoso', 'Pós-Chuva']}
                  onChange={(v: any) => setParams({...params, weather: v})}
                />
              </div>

              <SliderField 
                icon={Users} label="Entourage Humano" value={params.peopleCount} min={0} max={25}
                onChange={(v: number) => setParams({...params, peopleCount: v})}
              />
              <SliderField 
                icon={Car} label="Tráfego" value={params.carCount} min={0} max={20}
                onChange={(v: number) => setParams({...params, carCount: v})}
              />

              {/* Nova opção de Letreiro Iluminado */}
              <div className="space-y-4 pt-2">
                <div className="flex items-center justify-between p-4 bg-zinc-900/40 border border-white/5 rounded-2xl group hover:border-fuchsia-500/30 transition-all cursor-pointer select-none"
                     onClick={() => setParams({...params, illuminatedSignage: !params.illuminatedSignage})}>
                  <div className="flex items-center gap-3">
                    <Lightbulb className={`w-5 h-5 ${params.illuminatedSignage ? 'text-fuchsia-500' : 'text-zinc-600'}`} />
                    <div>
                      <span className="text-[10px] font-black text-zinc-300 uppercase tracking-widest block">Letreiro Iluminado</span>
                      <span className="text-[8px] font-medium text-zinc-500 uppercase tracking-tight">Manter cor da face original</span>
                    </div>
                  </div>
                  <div className={`w-10 h-5 rounded-full transition-all relative ${params.illuminatedSignage ? 'bg-fuchsia-600' : 'bg-zinc-800'}`}>
                    <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${params.illuminatedSignage ? 'left-6' : 'left-1'}`} />
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                  <Zap className="w-3 h-3" /> Materiais & Materia Prima
                </span>
                <textarea 
                  value={params.environmentDetails}
                  onChange={(e) => setParams({...params, environmentDetails: e.target.value})}
                  placeholder="ACM preto, vidro reflexivo, madeira cumaru..."
                  className="w-full bg-zinc-900/40 border border-white/5 rounded-2xl p-4 text-xs text-zinc-300 min-h-[100px] resize-none focus:border-fuchsia-500/50 outline-none"
                />
              </div>
            </div>

            <button
              onClick={async () => {
                if (!image) return;
                setLoading(true);
                try {
                  const data = await generateArchitecturalPrompt(image, params);
                  setResult(data);
                  saveToHistory(data);
                } catch (err) { console.error(err); } finally { setLoading(false); }
              }}
              disabled={!image || loading}
              className={`w-full py-6 rounded-3xl font-black text-sm uppercase tracking-[0.4em] transition-all shadow-xl active:scale-95 flex items-center justify-center gap-4 ${
                !image ? 'bg-zinc-800 text-zinc-600 opacity-50' : 'bg-white text-black hover:bg-fuchsia-50'
              }`}
            >
              {loading ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5 text-fuchsia-600" />}
              {loading ? 'ANALISANDO...' : 'EXECUTAR MOTOR'}
            </button>
          </div>
        </div>
      </main>

      <footer className="p-12 text-center border-t border-white/5 bg-zinc-950/50">
        <p className="text-[9px] font-black text-zinc-700 uppercase tracking-[0.5em]">FCD VIEWPROMPT © {new Date().getFullYear()} ARCHVIZ INTELLIGENCE LAB</p>
      </footer>

      <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Upload, Sun, Copy, Check, RefreshCw, Sparkles, 
  Palette, Focus, ChevronDown, Zap,
  Globe, Layout, Send, Users, Car, History, Eye, Trash2, Download, Lightbulb
} from 'lucide-react';
import { 
  PromptParameters, GeneratedPrompt, LightingMode, WeatherMode 
} from './types';
import { generateArchitecturalPrompt, generateSamplePreview } from './geminiService';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [previewLoading, setPreviewLoading] = useState(false);
  const [result, setResult] = useState<GeneratedPrompt | null>(null);
  const [history, setHistory] = useState<GeneratedPrompt[]>([]);
  const [copied, setCopied] = useState(false);
  const [isDragging, setIsDragging] = useState(false);

  const [params, setParams] = useState<PromptParameters>({
    socialFormat: 'Instagram / TikTok (9:16)',
    visualStyle: 'Hiper-realista',
    environmentType: 'Comercial/Urbano',
    cameraAngle: 'Nível do Olhar',
    lighting: 'Noturno',
    weather: 'Dia de Sol',
    peopleCount: 5,
    carCount: 2,
    environmentDetails: '',
    illuminatedSignage: false
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('fcd_history');
    if (saved) setHistory(JSON.parse(saved));
  }, []);

  const saveToHistory = (item: GeneratedPrompt) => {
    const newHistory = [item, ...history].slice(0, 10);
    setHistory(newHistory);
    localStorage.setItem('fcd_history', JSON.stringify(newHistory));
  };

  const processFile = (file: File) => {
    if (!file.type.startsWith('image/')) {
      alert('Por favor, selecione um arquivo de imagem válido.');
      return;
    }
    const reader = new FileReader();
    reader.onload = (event) => {
      if (event.target?.result) {
        setImage(event.target.result as string);
        setResult(null); // Limpa resultado anterior ao subir nova imagem
      }
    };
    reader.readAsDataURL(file);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      processFile(file);
      // Limpa o valor do input para permitir selecionar o mesmo arquivo novamente se necessário
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const generatePreview = async () => {
    if (!result || previewLoading) return;
    setPreviewLoading(true);
    try {
      const url = await generateSamplePreview(result.english, params.socialFormat);
      const updatedResult = { ...result, previewUrl: url };
      setResult(updatedResult);
      const newHistory = history.map(h => h.id === result.id ? updatedResult : h);
      setHistory(newHistory);
      localStorage.setItem('fcd_history', JSON.stringify(newHistory));
    } catch (err) {
      console.error('Erro ao gerar preview:', err);
    } finally {
      setPreviewLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const SelectField = ({ icon: Icon, label, value, options, onChange }: any) => (
    <div className="space-y-3 group/field">
      <div className="flex items-center gap-2.5 text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] group-hover/field:text-fuchsia-400 transition-colors">
        <Icon className="w-3.5 h-3.5" />
        {label}
      </div>
      <div className="relative">
        <select 
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="w-full bg-zinc-900/40 border border-white/5 rounded-2xl px-5 py-3.5 text-sm text-zinc-200 outline-none focus:border-fuchsia-500/50 focus:ring-4 focus:ring-fuchsia-500/10 appearance-none cursor-pointer pr-12 transition-all hover:bg-zinc-900/60"
        >
          {options.map((opt: string) => <option key={opt} value={opt} className="bg-zinc-900">{opt}</option>)}
        </select>
        <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 pointer-events-none text-zinc-500" />
      </div>
    </div>
  );

  const SliderField = ({ icon: Icon, label, value, min, max, onChange }: any) => (
    <div className="space-y-4 group/field">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-2.5 text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] group-hover/field:text-fuchsia-400 transition-colors">
          <Icon className="w-3.5 h-3.5" />
          {label}
        </div>
        <span className="text-xs font-black text-fuchsia-500 tabular-nums">{value}</span>
      </div>
      <input 
        type="range" min={min} max={max} value={value}
        onChange={(e) => onChange(parseInt(e.target.value))}
        className="w-full h-1 bg-zinc-800 rounded-full appearance-none cursor-pointer accent-fuchsia-500"
      />
    </div>
  );

  return (
    <div className="min-h-screen bg-[#050505] text-zinc-200 flex flex-col relative overflow-hidden">

      <div className="fixed top-[-10%] left-[-10%] w-[40%] h-[40%] bg-fuchsia-600/10 blur-[150px] pointer-events-none" />
      <div className="fixed bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[150px] pointer-events-none" />

      <header className="sticky top-0 z-50 glass-panel border-b border-white/5 px-10 py-5 flex items-center justify-between">
        <div className="flex items-center gap-5">
          <div className="relative group">
            <div className="absolute inset-0 bg-fuchsia-500 blur-lg opacity-20" />
            <div className="relative bg-gradient-to-br from-fuchsia-500 to-purple-700 p-2.5 rounded-2xl">
