                className="bg-zinc-900/40 border border-white/5 rounded-[40px] p-10 flex flex-col items-center justify-center aspect-square md:aspect-[4/3] cursor-pointer hover:bg-zinc-900/60 hover:border-fuchsia-500/50 transition-all group relative overflow-hidden"
              >
                {afterImage ? (
                   <>
                    <img src={afterImage} className="absolute inset-0 w-full h-full object-cover opacity-50 group-hover:opacity-30 transition-opacity" alt="Depois" />
                    <div className="z-10 bg-black/50 px-4 py-2 rounded-xl backdrop-blur-md">
                      <Check className="w-8 h-8 text-green-500" />
                    </div>
                    <p className="z-10 mt-4 font-black uppercase tracking-widest text-white text-xs">Imagem Carregada</p>
                  </>
                ) : (
                  <>
                    <div className="bg-zinc-800 p-6 rounded-full mb-6 group-hover:scale-110 transition-transform">
                      <Sparkles className="w-8 h-8 text-zinc-400 group-hover:text-fuchsia-400 transition-colors" />
                    </div>
                    <h3 className="text-lg font-black uppercase text-white mb-2">Depois</h3>
                    <p className="text-[10px] uppercase tracking-widest text-zinc-500 text-center">Render Final / Pós</p>
                  </>
                )}
              </div>
            </div>
          ) : (
            // Slider Component
            <div className="w-full max-w-5xl mx-auto space-y-6">
              <div 
                ref={containerRef}
                className="relative w-full aspect-video rounded-[30px] overflow-hidden cursor-ew-resize border border-white/10 shadow-2xl select-none"
                onMouseMove={handleSliderMove}
                onTouchMove={handleSliderMove}
                onClick={handleSliderMove}
              >
                {/* Imagem do 'Depois' (Fundo completo) */}
                <img 
                  src={afterImage} 
                  className="absolute inset-0 w-full h-full object-cover" 
                  alt="Depois" 
                  draggable={false}
                />

                {/* Imagem do 'Antes' (Recortada) */}
                <div 
                  className="absolute inset-0 overflow-hidden border-r-2 border-fuchsia-500"
                  style={{ width: `${sliderPosition}%` }}
                >
                  <img 
                    src={beforeImage} 
                    className="absolute inset-0 w-full h-full object-cover max-w-none" 
                    style={{ width: containerRef.current?.offsetWidth }}
                    alt="Antes" 
                    draggable={false}
                  />
                </div>

                {/* Handle / Puxador */}
                <div 
                  className="absolute top-0 bottom-0 w-10 -ml-5 flex items-center justify-center pointer-events-none"
                  style={{ left: `${sliderPosition}%` }}
                >
                  <div className="w-8 h-8 bg-fuchsia-500 rounded-full shadow-xl flex items-center justify-center border-2 border-white">
                    <ArrowRightLeft className="w-4 h-4 text-white" />
                  </div>
                </div>

                {/* Labels */}
                <div className="absolute top-6 left-6 bg-black/60 backdrop-blur-md px-4 py-2 rounded-lg border border-white/10 pointer-events-none">
                  <span className="text-[10px] font-black uppercase tracking-widest text-white">Antes</span>
                </div>
                <div className="absolute top-6 right-6 bg-fuchsia-600/80 backdrop-blur-md px-4 py-2 rounded-lg border border-white/10 pointer-events-none">
                  <span className="text-[10px] font-black uppercase tracking-widest text-white">Depois</span>
                </div>
              </div>

              <div className="flex justify-center">
                 <p className="text-[10px] text-zinc-500 uppercase tracking-[0.2em] animate-pulse">Arraste ou clique para comparar</p>
              </div>
            </div>
          )}
        </main>
      )}

      <footer className="p-12 text-center border-t border-white/5 bg-zinc-950/50">
        <p className="text-[9px] font-black text-zinc-700 uppercase tracking-[0.5em]">FCD VIEWPROMPT © {new Date().getFullYear()} ARCHVIZ INTELLIGENCE LAB</p>
      </footer>

      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept="image/png, image/jpeg, image/webp" 
        onChange={(e) => handleFileUpload(e, 'main')} 
      />
      <input 
        type="file" 
        ref={beforeInputRef} 
        className="hidden" 
        accept="image/png, image/jpeg, image/webp" 
        onChange={(e) => handleFileUpload(e, 'before')} 
      />
      <input 
        type="file" 
        ref={afterInputRef} 
        className="hidden" 
        accept="image/png, image/jpeg, image/webp" 
        onChange={(e) => handleFileUpload(e, 'after')} 
      />
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  Upload, Sun, Copy, Check, RefreshCw, Sparkles, 
  Palette, Focus, ChevronDown, Zap,
  Globe, Layout, Send, Users, Car, History, Eye, Trash2, Download, Lightbulb, Map, Wind, Camera, Footprints,
  ArrowRightLeft, ImageIcon, MoveHorizontal, X
} from 'lucide-react';
import { 
  PromptParameters, GeneratedPrompt, LightingMode, WeatherMode, SidewalkType 
} from './types';
import { generateArchitecturalPrompt, generateSamplePreview } from './geminiService';

type TabType = 'scene' | 'atmos' | 'entorno';
type AppMode = 'generator' | 'comparator';

const App: React.FC = () => {
  // Global App State
  const [appMode, setAppMode] = useState<AppMode>('generator');

  // Generator State
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [previewLoading, setPreviewLoading] = useState(false);
  const [result, setResult] = useState<GeneratedPrompt | null>(null);
  const [history, setHistory] = useState<GeneratedPrompt[]>([]);
  const [copied, setCopied] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('scene');

  // Comparator State
  const [beforeImage, setBeforeImage] = useState<string | null>(null);
  const [afterImage, setAfterImage] = useState<string | null>(null);
  const [sliderPosition, setSliderPosition] = useState(50);
  const containerRef = useRef<HTMLDivElement>(null);

  const [params, setParams] = useState<PromptParameters>({
    socialFormat: 'Instagram / TikTok (9:16)',
    visualStyle: 'Hiper-realista',
    environmentType: 'Urbano / Metrópole',
    cameraAngle: 'Nível do Olhar',
    lighting: 'Noturno',
    weather: 'Dia de Sol',
    peopleCount: 5,
    carCount: 2,
    environmentDetails: '',
    illuminatedSignage: false,
    sidewalkEnabled: true,
    sidewalkType: 'Concreto Clássico'
  });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const beforeInputRef = useRef<HTMLInputElement>(null);
  const afterInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('fcd_history');
    if (saved) setHistory(JSON.parse(saved));
  }, []);

  const saveToHistory = (item: GeneratedPrompt) => {
    const newHistory = [item, ...history].slice(0, 10);
    setHistory(newHistory);
    localStorage.setItem('fcd_history', JSON.stringify(newHistory));
  };

  const processFile = (file: File, target: 'main' | 'before' | 'after') => {
    if (!file.type.startsWith('image/')) {
      alert('Por favor, selecione um arquivo de imagem válido.');
      return;
    }
    const reader = new FileReader();
    reader.onload = (event) => {
      if (event.target?.result) {
        const resultUrl = event.target.result as string;
        if (target === 'main') {
          setImage(resultUrl);
          setResult(null);
        } else if (target === 'before') {
          setBeforeImage(resultUrl);
        } else if (target === 'after') {
          setAfterImage(resultUrl);
        }
      }
    };
    reader.readAsDataURL(file);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'main' | 'before' | 'after') => {
    const file = e.target.files?.[0];
    if (file) {
      processFile(file, target);
      e.target.value = '';
    }
  };

  const handleDrop = (e: React.DragEvent, target: 'main' | 'before' | 'after') => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file) {
      processFile(file, target);
    }
  };

  const handleSliderMove = useCallback((e: React.MouseEvent | React.TouchEvent) => {
    if (containerRef.current) {
      const rect = containerRef.current.getBoundingClientRect();
      const x = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
      const position = ((x - rect.left) / rect.width) * 100;
      setSliderPosition(Math.min(100, Math.max(0, position)));
    }
  }, []);

  const generatePreview = async () => {
    if (!result || previewLoading) return;
    setPreviewLoading(true);
    try {
      const url = await generateSamplePreview(result.english, params.socialFormat);
      const updatedResult = { ...result, previewUrl: url };
      setResult(updatedResult);
      const newHistory = history.map(h => h.id === result.id ? updatedResult : h);
      setHistory(newHistory);
      localStorage.setItem('fcd_history', JSON.stringify(newHistory));
    } catch (err) {
      console.error('Erro ao gerar preview:', err);
    } finally {
      setPreviewLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const SelectField = ({ icon: Icon, label, value, options, onChange, disabled }: any) => (
    <div className={`space-y-3 group/field ${disabled ? 'opacity-40 pointer-events-none' : ''}`}>
      <div className="flex items-center gap-2.5 text-[11px] font-black text-zinc-400 uppercase tracking-[0.2em] group-hover/field:text-fuchsia-400 transition-colors">
        <Icon className="w-4 h-4" />
        {label}
      </div>
      <div className="relative">
        <select 
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="w-full bg-zinc-900/40 border border-white/5 rounded-2xl px-5 py-4 text-sm text-zinc-100 outline-none focus:border-fuchsia-500/50 focus:ring-4 focus:ring-fuchsia-500/10 appearance-none cursor-pointer pr-12 transition-all hover:bg-zinc-900/60"
        >
          {options.map((opt: string) => <option key={opt} value={opt} className="bg-zinc-900">{opt}</option>)}
        </select>
        <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 pointer-events-none text-zinc-500" />
      </div>
    </div>
  );

  const SliderField = ({ icon: Icon, label, value, min, max, onChange }: any) => (
    <div className="space-y-4 group/field">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-2.5 text-[11px] font-black text-zinc-400 uppercase tracking-[0.2em] group-hover/field:text-fuchsia-400 transition-colors">
          <Icon className="w-4 h-4" />
          {label}
        </div>
        <span className="text-sm font-black text-fuchsia-500 tabular-nums">{value}</span>
      </div>
      <input 
        type="range" min={min} max={max} value={value}
        onChange={(e) => onChange(parseInt(e.target.value))}
        className="w-full h-1.5 bg-zinc-800 rounded-full appearance-none cursor-pointer accent-fuchsia-500"
      />
    </div>
  );

  return (
    <div className="min-h-screen bg-[#050505] text-zinc-200 flex flex-col relative overflow-hidden">

      <div className="fixed top-[-10%] left-[-10%] w-[40%] h-[40%] bg-fuchsia-600/10 blur-[150px] pointer-events-none" />
      <div className="fixed bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[150px] pointer-events-none" />

      <header className="sticky top-0 z-50 glass-panel border-b border-white/5 px-6 md:px-10 py-6 flex items-center justify-between">
        <div className="flex items-center gap-5">
          <div className="relative group">
            <div className="absolute inset-0 bg-fuchsia-500 blur-lg opacity-20" />
            <div className="relative bg-gradient-to-br from-fuchsia-500 to-purple-700 p-2.5 rounded-2xl">
              <Sparkles className="w-6 h-6 text-white" />
            </div>
          </div>
          <h1 className="text-2xl md:text-3xl font-black tracking-tighter text-white uppercase italic hidden md:block">
            FCD <span className="text-fuchsia-500">VIEW</span>PROMPT
          </h1>
          <h1 className="text-2xl font-black tracking-tighter text-white uppercase italic md:hidden">
            FCD<span className="text-fuchsia-500">VP</span>
          </h1>
        </div>

        <div className="flex bg-zinc-900/50 p-1.5 rounded-2xl border border-white/5">
           <button 
             onClick={() => setAppMode('generator')}
             className={`px-5 py-2.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all flex items-center gap-2 ${appMode === 'generator' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-zinc-300'}`}
           >
             <Zap className="w-3.5 h-3.5" /> <span className="hidden sm:inline">Generator</span>
           </button>
           <button 
             onClick={() => setAppMode('comparator')}
             className={`px-5 py-2.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all flex items-center gap-2 ${appMode === 'comparator' ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-500/20' : 'text-zinc-500 hover:text-zinc-300'}`}
           >
             <ArrowRightLeft className="w-3.5 h-3.5" /> <span className="hidden sm:inline">Compare</span>
           </button>
        </div>

        <div className="flex items-center gap-4">
          {appMode === 'generator' && image && (
            <button 
              onClick={() => { setImage(null); setResult(null); }} 
              className="text-[11px] font-black text-zinc-400 hover:text-white uppercase tracking-widest flex items-center gap-2"
            >
              <RefreshCw className="w-3.5 h-3.5" /> <span className="hidden md:inline">Resetar</span>
            </button>
          )}
          {appMode === 'comparator' && (beforeImage || afterImage) && (
            <button 
              onClick={() => { setBeforeImage(null); setAfterImage(null); }} 
              className="text-[11px] font-black text-zinc-400 hover:text-white uppercase tracking-widest flex items-center gap-2"
            >
              <RefreshCw className="w-3.5 h-3.5" /> <span className="hidden md:inline">Limpar</span>
            </button>
          )}
        </div>
      </header>

      {/* GENERATOR MODE */}
      {appMode === 'generator' && (
        <main className="flex-1 max-w-[1600px] mx-auto w-full p-6 md:p-10 grid grid-cols-1 lg:grid-cols-12 gap-8 md:gap-12 animate-in fade-in duration-500">

          <div className="hidden xl:block lg:col-span-1 space-y-4">
            <div className="flex flex-col items-center gap-6">
              <History className="w-6 h-6 text-zinc-600" />
              <div className="flex flex-col gap-4">
                {history.map(item => (
                  <button 
                    key={item.id}
                    onClick={() => setResult(item)}
                    className={`w-14 h-14 rounded-2xl border transition-all overflow-hidden ${result?.id === item.id ? 'border-fuchsia-500 scale-110 shadow-lg shadow-fuchsia-500/20' : 'border-white/5 opacity-40 hover:opacity-100'}`}
                  >
                     <div className="w-full h-full bg-zinc-900 flex items-center justify-center text-[11px] font-bold">
                       #{item.id.slice(0, 3)}
                     </div>
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="lg:col-span-11 xl:col-span-7 space-y-12">
            <div 
              onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
              onDragLeave={() => setIsDragging(false)}
              onDrop={(e) => handleDrop(e, 'main')}
              className={`relative group rounded-[35px] md:rounded-[45px] overflow-hidden bg-zinc-900/40 border transition-all duration-500 flex flex-col items-center justify-center ${
                image ? 'aspect-video' : 'min-h-[380px] lg:aspect-video' 
              } ${isDragging ? 'border-fuchsia-500 bg-fuchsia-500/5 scale-[0.99]' : 'border-white/5'}`}
            >
              {image ? (
                <div className="w-full h-full relative group">
                  <img src={image} className="w-full h-full object-cover" alt="Projeto" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-8">
                     <button onClick={() => fileInputRef.current?.click()} className="bg-white text-black px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl">Trocar Snapshot</button>
                  </div>
                  {loading && <div className="scan-line" />}
                </div>
              ) : (
                <div className="text-center p-8 md:p-12 w-full">
                  <div className="bg-zinc-900 p-8 md:p-10 rounded-full inline-block mb-8 border border-white/5 shadow-2xl shadow-black/50">
                    <Upload className={`w-10 h-10 md:w-14 md:h-14 ${isDragging ? 'text-fuchsia-500' : 'text-zinc-700'}`} />
                  </div>
                  <h3 className="text-xl md:text-3xl font-black mb-3 uppercase tracking-tighter text-zinc-100">Arraste seu Render</h3>
                  <p className="text-zinc-400 text-xs md:text-sm uppercase tracking-widest mb-10 max-w-[240px] md:max-w-none mx-auto leading-relaxed">Snapshot direto do seu software 3D</p>
                  <button 
                    onClick={() => fileInputRef.current?.click()} 
                    className="bg-white text-black px-10 py-4 md:px-12 md:py-5 rounded-2xl font-black text-xs md:text-sm uppercase tracking-widest hover:scale-105 hover:bg-zinc-200 transition-all shadow-2xl"
                  >
                    Selecionar Arquivo
                  </button>
                </div>
              )}
            </div>

            {result && (
              <div className="space-y-10 animate-in fade-in slide-in-from-bottom-8 duration-700">
                <div className="glass-panel rounded-[40px] p-8 md:p-12 space-y-10">
                  <div className="flex flex-col md:flex-row items-start md:items-center justify-between border-b border-white/5 pb-10 gap-6">
                     <div className="flex items-center gap-5">
                       <div className="w-14 h-14 bg-fuchsia-500/10 rounded-2xl flex items-center justify-center flex-shrink-0">
                         <Zap className="w-8 h-8 text-fuchsia-400" />
                       </div>
                       <div>
                         <h2 className="text-2xl font-black uppercase italic tracking-tight">AI Prompt Engine</h2>
                         <p className="text-[11px] font-bold text-zinc-400 uppercase tracking-widest">Otimizado para Midjourney v6.1</p>
                       </div>
                     </div>
                     <button 
                      onClick={() => copyToClipboard(result.english)}
                      className={`flex items-center gap-3 px-8 py-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all w-full md:w-auto justify-center shadow-lg ${copied ? 'bg-green-600' : 'bg-fuchsia-600 hover:bg-fuchsia-500'}`}
                    >
                      {copied ? <Check className="w-5 h-5" /> : <Copy className="w-5 h-5" />} 
                      {copied ? 'Copiado' : 'Copiar Tudo'}
                    </button>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                    <div className="space-y-8">
                      <div>
                        <span className="text-[11px] font-black text-zinc-500 uppercase tracking-[0.3em] block mb-4">Prompt Estruturado</span>
                        <div className="bg-black/40 p-8 rounded-[32px] border border-white/5 text-base md:text-lg leading-relaxed text-zinc-200 min-h-[180px] whitespace-pre-wrap font-medium">
                          {result.english}
                        </div>
                      </div>
                      <div>
                        <span className="text-[11px] font-black text-zinc-500 uppercase tracking-[0.3em] block mb-4">Tags de Laboratório</span>
                        <div className="flex flex-wrap gap-2.5">
                          {result.tags.map(t => <span key={t} className="bg-white/5 border border-white/5 px-4 py-2 rounded-xl text-xs font-bold text-zinc-300">#{t}</span>)}
                        </div>
                      </div>
                    </div>

                    <div className="space-y-8">
                      <span className="text-[11px] font-black text-zinc-500 uppercase tracking-[0.3em] block mb-4">Preview de Amostra (IA)</span>
                      <div className="relative aspect-square bg-zinc-900 rounded-[32px] border border-white/5 overflow-hidden group shadow-2xl">
                        {result.previewUrl ? (
                          <img src={result.previewUrl} className="w-full h-full object-cover" alt="Preview IA" />
                        ) : (
                          <div className="w-full h-full flex flex-col items-center justify-center p-10 text-center">
                            <Eye className="w-10 h-10 text-zinc-700 mb-6" />
                            <p className="text-xs md:text-sm font-bold text-zinc-400 uppercase leading-relaxed tracking-wide">Gere uma prévia visual para testar a fidelidade do prompt</p>
                          </div>
                        )}

                        {previewLoading && (
                          <div className="absolute inset-0 bg-black/70 backdrop-blur-md flex items-center justify-center">
                            <RefreshCw className="w-10 h-10 animate-spin text-fuchsia-500" />
                          </div>
                        )}

                        {!result.previewUrl && !previewLoading && (
                          <button 
                            onClick={generatePreview}
                            className="absolute inset-0 flex items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity"
                          >
                            <span className="bg-white text-black px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl">Gerar Preview Visual</span>
                          </button>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>

          <div className="lg:col-span-12 xl:col-span-4 sticky top-10 self-start">
            <div className="glass-panel rounded-[45px] p-8 md:p-10 space-y-10 shadow-2xl relative overflow-hidden">
              <div className="flex items-center gap-2 p-1.5 bg-black/40 border border-white/5 rounded-[22px] mb-4">
                <button 
                  onClick={() => setActiveTab('scene')}
                  className={`flex-1 flex items-center justify-center gap-2.5 py-3.5 rounded-[18px] text-[11px] font-black uppercase tracking-wider transition-all ${activeTab === 'scene' ? 'bg-fuchsia-600 text-white shadow-xl shadow-fuchsia-500/20' : 'text-zinc-500 hover:text-zinc-300'}`}
                >
                  <Camera className="w-4 h-4" /> <span className="inline">Cena</span>
                </button>
                <button 
                  onClick={() => setActiveTab('atmos')}
                  className={`flex-1 flex items-center justify-center gap-2.5 py-3.5 rounded-[18px] text-[11px] font-black uppercase tracking-wider transition-all ${activeTab === 'atmos' ? 'bg-fuchsia-600 text-white shadow-xl shadow-fuchsia-500/20' : 'text-zinc-500 hover:text-zinc-300'}`}
                >
                  <Wind className="w-4 h-4" /> <span className="inline">Atmos</span>
                </button>
                <button 
                  onClick={() => setActiveTab('entorno')}
                  className={`flex-1 flex items-center justify-center gap-2.5 py-3.5 rounded-[18px] text-[11px] font-black uppercase tracking-wider transition-all ${activeTab === 'entorno' ? 'bg-fuchsia-600 text-white shadow-xl shadow-fuchsia-500/20' : 'text-zinc-500 hover:text-zinc-300'}`}
