              >
                {loading ? <RefreshCw className="w-6 h-6 animate-spin" /> : <Sparkles className="w-6 h-6 text-fuchsia-600" />}
                {loading ? 'PROCESSANDO...' : 'GERAR MASTER PROMPT'}
              </button>
            </div>
          </div>
        </main>
      )}

      {/* COMPARATOR MODE */}
      {appMode === 'comparator' && (
