                   <>
                    <img src={afterImage} className="absolute inset-0 w-full h-full object-cover opacity-50 group-hover:opacity-30 transition-opacity" alt="Depois" />
                    <div className="z-10 bg-black/60 px-6 py-3 rounded-2xl backdrop-blur-md border border-white/10">
                      <Check className="w-10 h-10 text-green-500" />
                    </div>
                    <p className="z-10 mt-6 font-black uppercase tracking-[0.2em] text-white text-sm">Render Final OK</p>
                  </>
                ) : (
                  <>
                    <div className="bg-zinc-800 p-8 rounded-full mb-8 group-hover:scale-110 transition-transform shadow-xl">
                      <Sparkles className="w-10 h-10 text-zinc-400 group-hover:text-fuchsia-400 transition-colors" />
                    </div>
                    <h3 className="text-xl font-black uppercase text-white mb-3">Render Depois</h3>
                    <p className="text-xs uppercase tracking-widest text-zinc-500 text-center leading-relaxed">Arraste sua visualização final fotorrealista</p>
                  </>
                )}
              </div>
            </div>
          ) : (
            // Slider Component
            <div className="w-full max-w-6xl mx-auto space-y-8 animate-in zoom-in-95 duration-500">
              <div 
                ref={containerRef}
                className="relative w-full aspect-video rounded-[40px] md:rounded-[55px] overflow-hidden cursor-ew-resize border border-white/10 shadow-[0_35px_60px_-15px_rgba(0,0,0,0.8)] select-none"
                onMouseMove={handleSliderMove}
                onTouchMove={handleSliderMove}
                onClick={handleSliderMove}
              >
                {/* Imagem do 'Depois' (Fundo completo) */}
                <img 
                  src={afterImage} 
                  className="absolute inset-0 w-full h-full object-cover" 
                  alt="Depois" 
                  draggable={false}
                />

                {/* Imagem do 'Antes' (Recortada) */}
                <div 
                  className="absolute inset-0 overflow-hidden border-r-2 border-fuchsia-500/80 shadow-[10px_0_30px_rgba(217,70,239,0.3)]"
                  style={{ width: `${sliderPosition}%` }}
                >
                  <img 
                    src={beforeImage} 
                    className="absolute inset-0 w-full h-full object-cover max-w-none" 
                    style={{ width: containerRef.current?.offsetWidth }}
                    alt="Antes" 
                    draggable={false}
                  />
                </div>

                {/* Handle / Puxador */}
                <div 
                  className="absolute top-0 bottom-0 w-12 -ml-6 flex items-center justify-center pointer-events-none"
                  style={{ left: `${sliderPosition}%` }}
                >
                  <div className="w-12 h-12 bg-fuchsia-500 rounded-full shadow-2xl flex items-center justify-center border-[3px] border-white scale-110">
                    <ArrowRightLeft className="w-6 h-6 text-white" />
                  </div>
                </div>

                {/* Labels flutuantes com fontes maiores */}
                <div className="absolute top-8 left-8 bg-black/70 backdrop-blur-xl px-6 py-3 rounded-2xl border border-white/10 shadow-2xl pointer-events-none">
                  <span className="text-xs md:text-sm font-black uppercase tracking-[0.2em] text-white">PROJETO BASE</span>
                </div>
                <div className="absolute top-8 right-8 bg-fuchsia-600/90 backdrop-blur-xl px-6 py-3 rounded-2xl border border-white/10 shadow-2xl pointer-events-none">
                  <span className="text-xs md:text-sm font-black uppercase tracking-[0.2em] text-white">VISUALIZAÇÃO FINAL</span>
                </div>
              </div>

              <div className="flex justify-center flex-col items-center gap-4">
                 <p className="text-xs font-bold text-zinc-400 uppercase tracking-[0.3em] animate-pulse">Deslize lateralmente para comparar detalhes</p>
                 <button 
                  onClick={() => { setBeforeImage(null); setAfterImage(null); }}
                  className="bg-white/5 hover:bg-white/10 border border-white/10 px-8 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] transition-all"
