          )}
        </main>
      )}

      <footer className="p-16 text-center border-t border-white/5 bg-zinc-950/50">
        <p className="text-[11px] font-black text-zinc-600 uppercase tracking-[0.6em] mb-4">FCD VIEWPROMPT</p>
        <p className="text-[10px] font-bold text-zinc-700 uppercase tracking-[0.3em]">© {new Date().getFullYear()} ARCHVIZ INTELLIGENCE LAB • HIGH END RENDERING TOOLS</p>
      </footer>

      <input 
        type="file" 
