      <input 
        type="file" 
        ref={beforeInputRef} 
        className="hidden" 
        accept="image/png, image/jpeg, image/webp" 
        onChange={(e) => handleFileUpload(e, 'before')} 
      />
      <input 
        type="file" 
        ref={afterInputRef} 
        className="hidden" 
        accept="image/png, image/jpeg, image/webp" 
