import { GoogleGenAI, Type } from "@google/genai";
import { PromptParameters, GeneratedPrompt } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateArchitecturalPrompt = async (
  imageData: string,
  params: PromptParameters
): Promise<GeneratedPrompt> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "image/jpeg",
            data: imageData.split(',')[1],
          },
        },
        {
          text: `Você é um diretor de arte sênior especializado em Architectural Visualization (ArchViz). Analise a imagem fornecida e crie um prompt mestre otimizado para Midjourney v6.1.

            DADOS DA CENA:
            - Tipo de Projeto: ${params.projectType}
            - Formato: ${params.socialFormat}
            - Estética Visual: ${params.visualStyle}
            - Ângulo de Câmera: ${params.cameraAngle}

            CONFIGURAÇÃO ATMOSFÉRICA:
            - Iluminação: ${params.lighting}
            - Clima: ${params.weather}
            - Letreiro Iluminado: ${params.illuminatedSignage ? "Ativado (Efeito halo/backlit channel letters, mantendo a face das letras na cor original do projeto)" : "Desativado"}

            DETALHES DO ENTORNO & CALÇADA (CRÍTICO):
            - Tipo de Ambiente: ${params.environmentType}
            - Calçada/Passeio: ${params.sidewalkEnabled ? `Incluir calçada frontal com acabamento em ${params.sidewalkType}.` : "Sem calçada frontal, integração direta com o solo/ambiente."}
            - População: ${params.peopleCount} pessoas em escala humana realista.
            - Veículos: ${params.carCount} veículos modernos e elegantes.
            - Detalhes Adicionais: ${params.environmentDetails}

            Gere um JSON estritamente com:
            1. 'english': Prompt técnico ultra-detalhado em inglês. Inclua termos de renderização profissional (octane render, unreal engine 5, raytracing), descrição precisa dos materiais baseada na imagem e integração orgânica com o ambiente de ${params.environmentType}. Se for Planta ou Detalhamento Técnico, foque em clareza, linhas precisas e estilo blueprint profissional.
            2. 'portuguese': Breve justificativa das escolhas técnicas de iluminação e entorno.
            3. 'tags': 5 keywords poderosas.

            Importante: O prompt deve ser coeso, evocativo e focado em realismo fotográfico de alto nível (ou precisão técnica se for planta/detalhamento).`
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          english: { type: Type.STRING },
          portuguese: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["english", "portuguese", "tags"]
      }
    }
  });

  const data = JSON.parse(response.text || '{}');
  return {
    ...data,
    id: Math.random().toString(36).substr(2, 9),
    timestamp: Date.now()
  };
};

export const generateSamplePreview = async (prompt: string, aspectRatio: string): Promise<string> => {
  const ratioMap: Record<string, "1:1" | "3:4" | "4:3" | "9:16" | "16:9"> = {
    'Instagram / TikTok (9:16)': "9:16",
    'Instagram Portrait (4:5)': "3:4",
    'Post / Feed (1:1)': "1:1",
    'YouTube / TV (16:9)': "16:9",
    'Fotografia (3:2)': "4:3",
    'Cinematográfico (2.35:1)': "16:9",
    'Vertical Clássico (2:3)': "3:4"
  };

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `Professional high-end architectural visualization photography, realistic materials, detailed environment, ${prompt}` }],
    },
    config: {
      imageConfig: {
        aspectRatio: ratioMap[aspectRatio] || "1:1"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Falha ao gerar preview");
};

